const eventData = $('🏷️ Detect Credit Note').first().json;
const bodyPreview = eventData.body_preview || '';
const hasFiles = (eventData.file_ids || []).length > 0;

// Invoice indicators in email body
const invoicePatterns = [
  /rechnung/i, /invoice/i, /receipt/i, /quittung/i,
  /betrag|amount|total|summe/i,
  /€|\$|EUR|USD/,
  /\d+[.,]\d{2}/,
  /zahlungsziel|payment.?due|fällig/i,
  /rechnungsnummer|invoice.?(?:no|number|nr)/i
];

const matchCount = invoicePatterns.filter(p => p.test(bodyPreview)).length;
// Need at least 3 indicators AND body must have content
const looksLikeInvoice = bodyPreview.length > 50 && matchCount >= 3;

return {
  json: {
    ...eventData,
    body_preview: bodyPreview,
    body_looks_like_invoice: looksLikeInvoice,
    body_match_count: matchCount,
    has_files: hasFiles,
    extraction_source: looksLikeInvoice ? 'EMAIL_BODY' : (hasFiles ? 'ATTACHMENT' : 'NONE')
  }
};

