// FIX 1: Split file_ids into individual items for multi-attachment processing
const eventData = $('🔍 Check Email Body').first().json;
const fileIds = eventData.file_ids || [];

return fileIds.map((fileId, index) => {
  // Generate unique invoice_id per attachment
  const invoiceId = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });

  return {
    json: {
      file_id: fileId,
      file_index: index,
      invoice_id: invoiceId,
      idempotency_key: `m6_${eventData.superchat_message_id}_${index}`,

      // Pass through all event data
      superchat_message_id: eventData.superchat_message_id,
      superchat_conversation_id: eventData.superchat_conversation_id,
      email_from: eventData.email_from,
      email_subject: eventData.email_subject,
      email_received_at: eventData.email_received_at,
      doc_type: eventData.doc_type,
      invoice_type: eventData.invoice_type || 'invoice',
      confidence: eventData.confidence
    }
  };
});

const response = $input.first().json;

// Superchat API returns { results: [...] } or direct object
const file = response.results ? response.results[0] : response;

if (!file || !file.link || !file.link.url) {
  throw new Error(`Keine Download-URL gefunden. Response keys: ${Object.keys(response).join(', ')}`);
}

return {
  json: {
    file_id: file.id,
    filename: file.name,
    mime_type: file.mime_type,
    download_url: file.link.url
  }
};

// Prepare for Claude Vision & Storage upload
// V4: invoice_id comes from Split File IDs (per attachment)
const splitData = $('🔄 Split File IDs').item.json;
const binary = $input.first().binary;

// Get binary key (usually 'data')
const binaryKey = Object.keys(binary || {})[0] || 'data';
const binaryData = binary?.[binaryKey];

const invoiceId = splitData.invoice_id;
const storagePath = `receipts/${invoiceId}.pdf`;

return {
  json: {
    invoice_id: invoiceId,
    storage_path: storagePath,
    storage_filename: `${invoiceId}.pdf`,
    original_filename: binaryData?.fileName || 'invoice.pdf',
    mime_type: binaryData?.mimeType || 'application/pdf',
    binary_key: binaryKey,
    extraction_source: 'ATTACHMENT',

    // Pass through metadata from Split File IDs
    superchat_message_id: splitData.superchat_message_id,
    superchat_conversation_id: splitData.superchat_conversation_id,
    email_from: splitData.email_from,
    email_subject: splitData.email_subject,
    email_received_at: splitData.email_received_at,
    doc_type: splitData.doc_type,
    invoice_type: splitData.invoice_type,
    idempotency_key: splitData.idempotency_key,
    file_index: splitData.file_index
  },
  binary: binary
};

// Parse Claude response and merge with upload data
// V4: Support both attachment path (Claude Vision) and inline path (Claude Text Extract)
// FIX 3: Extract project_reference and delivery_address
let uploadData, claudeResponse;

try {
  // Try inline path first
  uploadData = $('📋 Prepare Text Result').first().json;
  const claudeNode = $('🤖 Claude Text Extract').first().json;
  if (claudeNode.content && Array.isArray(claudeNode.content)) {
    claudeResponse = claudeNode.content[0]?.text;
  } else {
    claudeResponse = claudeNode.content || claudeNode.text || JSON.stringify(claudeNode);
  }
} catch (e) {
  // Fall back to attachment path
  uploadData = $('🔧 Prepare Upload').item.json;
  const claudeNode = $('🤖 Claude Vision').item.json;
  if (claudeNode.content && Array.isArray(claudeNode.content)) {
    claudeResponse = claudeNode.content[0]?.text;
  } else {
    claudeResponse = claudeNode.content || claudeNode.text || JSON.stringify(claudeNode);
  }
}

// Clean response - remove markdown
let cleanJson = claudeResponse;
if (typeof cleanJson === 'string') {
  cleanJson = cleanJson.replace(/```json\s*/gi, '');
  cleanJson = cleanJson.replace(/```\s*/g, '');
  cleanJson = cleanJson.trim();
}

let parsed;
try {
  parsed = JSON.parse(cleanJson);
} catch (e) {
  throw new Error(`JSON Parse Error: ${e.message}\n\nRaw:\n${cleanJson.substring(0, 500)}`);
}

// V2: Smart net/gross handling - trust Claude when both provided, fallback to calculation
const vatPercent = parsed.rechnung?.mwst_prozent || 19;
const rawGross = Number(parsed.rechnung?.summe_brutto) || 0;
const rawNet = Number(parsed.rechnung?.summe_netto) || 0;

let grossAmount, netAmount;

if (rawNet > 0 && rawGross > 0) {
  // Both provided — validate plausibility
  const expectedGross = Math.round(rawNet * (1 + vatPercent / 100) * 100) / 100;
  if (Math.abs(expectedGross - rawGross) < 1.0) {
    grossAmount = rawGross;
    netAmount = rawNet;
  } else {
    // Inconsistent — trust brutto (Endpreis)
    grossAmount = rawGross;
    netAmount = Math.round((rawGross / (1 + vatPercent / 100)) * 100) / 100;
  }
} else if (rawGross > 0) {
  grossAmount = rawGross;
  netAmount = Math.round((rawGross / (1 + vatPercent / 100)) * 100) / 100;
} else if (rawNet > 0) {
  netAmount = rawNet;
  grossAmount = Math.round(rawNet * (1 + vatPercent / 100) * 100) / 100;
} else {
  grossAmount = 0;
  netAmount = 0;
}

// Type mapping
const typeMapping = {
  'BAUMARKT': 'BAUMARKT',
  'GROSSHANDEL': 'GROSSHANDEL',
  'FACHHANDEL': 'FACHHANDEL',
  'HERSTELLER': 'HERSTELLER',
  'ONLINE': 'ONLINE',
  'TANKSTELLE': 'SONSTIGE',
  'RESTAURANT': 'SONSTIGE',
  'SOFTWARE': 'SONSTIGE',
  'SONSTIGE': 'SONSTIGE'
};

// Escape SQL
const escapeSql = (str) => str ? String(str).replace(/'/g, "''") : '';

// Supplier code
let supplierCode = parsed.lieferant?.code || parsed.lieferant?.name?.substring(0, 4) || 'UNBK';
supplierCode = supplierCode.toUpperCase().replace(/[^A-Z]/g, '').substring(0, 4);
if (supplierCode.length < 2) supplierCode = 'UNBK';

// Payment data with defaults
const zahlung = parsed.zahlung || {};
const rechnungsDatum = parsed.rechnung?.datum || new Date().toISOString().split('T')[0];
const zahlungszielTage = zahlung.zahlungsziel_tage || 14;

// Calculate due date if not provided
let faelligAm = zahlung.faellig_am;
if (!faelligAm) {
  const d = new Date(rechnungsDatum);
  d.setDate(d.getDate() + zahlungszielTage);
  faelligAm = d.toISOString().split('T')[0];
}

// FIX 3: Project reference extraction
const projectReference = parsed.projekt?.project_reference || '';
const deliveryAddress = parsed.projekt?.delivery_address || '';

return {
  json: {
    invoice_id: uploadData.invoice_id,
    storage_path: uploadData.storage_path || '',
    original_filename: uploadData.original_filename,
    binary_key: uploadData.binary_key,
    extraction_source: uploadData.extraction_source || 'ATTACHMENT',

    // Superchat metadata
    superchat_message_id: uploadData.superchat_message_id,
    superchat_conversation_id: uploadData.superchat_conversation_id,
    email_from: escapeSql(uploadData.email_from || ''),
    email_subject: escapeSql(uploadData.email_subject || ''),
    email_received_at: uploadData.email_received_at,
    doc_type: uploadData.doc_type,
    invoice_type: uploadData.invoice_type || 'invoice',

    // Supplier
    lieferant_name: parsed.lieferant?.name || 'UNBEKANNT',
    lieferant_name_escaped: escapeSql(parsed.lieferant?.name || 'UNBEKANNT'),
    lieferant_code: supplierCode,
    lieferant_typ: typeMapping[parsed.lieferant?.typ] || 'SONSTIGE',

    expense_category: parsed.expense_category || 'MATERIAL',

    // Invoice
    rechnung_nummer: parsed.rechnung?.nummer || `SC-${uploadData.invoice_id.substring(0, 8)}`,
    rechnung_datum: rechnungsDatum,
    summe_brutto: grossAmount,
    summe_netto: netAmount,
    mwst_prozent: vatPercent,

    // Payment
    payment_iban: zahlung.iban || '',
    payment_bic: zahlung.bic || '',
    payment_terms_days: zahlungszielTage,
    due_date: faelligAm,
    discount_percent: zahlung.skonto_prozent || 0,
    discount_days: zahlung.skonto_tage || 0,

    // Positions
    positionen: parsed.positionen || [],
    positionen_count: (parsed.positionen || []).length,

    // FIX 3: Project reference
    project_reference: projectReference,
    delivery_address: deliveryAddress,

    needs_assignment: ['MATERIAL', 'SUBCONTRACTOR', 'ENTERTAINMENT'].includes(parsed.expense_category)
  }
};

// Get parsed data from previous node
const parsed = $input.first().json;

// Check if we have binary data (attachment path only)
let binary = {};
try {
  const downloadNode = $('📎 Download Binary').first();
  binary = downloadNode.binary || {};
} catch (e) {
  // Inline path - no binary available, that's fine
}

// Pass everything through
const result = { json: { ...parsed } };
if (Object.keys(binary).length > 0) {
  result.binary = binary;
}
return [result];

// Get original parsed data
const parsed = $('📋 Parse JSON').first().json;

// Get Gemini response
const geminiResponse = $input.first().json;

let result = { ...parsed };

// Parse Gemini response
let validatorData;
try {
  const text = geminiResponse.content?.parts?.[0]?.text || 
               geminiResponse.text || 
               JSON.stringify(geminiResponse);
  const cleanJson = text.replace(/```json\s*/gi, '').replace(/```/g, '').trim();
  validatorData = JSON.parse(cleanJson);
} catch (e) {
  return [{ 
    json: { 
      ...result, 
      _validation_skipped: true,
      _validation_error: e.message 
    }
  }];
}

// Apply corrections
if (validatorData.corrections) {
  for (const [key, value] of Object.entries(validatorData.corrections)) {
    result[key] = value;
  }
}

// Recalculate due_date if datum corrected
if (validatorData.corrections?.rechnung_datum) {
  const d = new Date(validatorData.corrections.rechnung_datum);
  d.setDate(d.getDate() + (result.payment_terms_days || 14));
  result.due_date = d.toISOString().split('T')[0];
}

// Recalculate net/gross if corrected
if (validatorData.corrections?.summe_brutto || validatorData.corrections?.summe_netto) {
  const vat = result.mwst_prozent || 19;
  if (validatorData.corrections.summe_brutto && !validatorData.corrections.summe_netto) {
    result.summe_netto = Math.round((result.summe_brutto / (1 + vat / 100)) * 100) / 100;
  } else if (validatorData.corrections.summe_netto && !validatorData.corrections.summe_brutto) {
    result.summe_brutto = Math.round(result.summe_netto * (1 + vat / 100) * 100) / 100;
  }
}

// Add validation metadata
result._validated = validatorData.valid;
result._confidence = validatorData.confidence;
result._issues = validatorData.issues || [];

return [{ json: result }];
